import { useState } from "react";
import "./Books.css";

function Books() {
  // Books data
  const booksData = [
    {
      id: 1,
      title: "React Basics",
      author: "Dan Abramov",
      price: 499,
      image: "https://m.media-amazon.com/images/I/61Iz2yy2CKL.jpg",
      description: "Learn the fundamentals of React step by step."
    },
    {
      id: 2,
      title: "JavaScript Guide",
      author: "Brendan Eich",
      price: 399,
      image: "data:image/jpeg;base64,",
      description: "Deep dive into JavaScript concepts."
    },
    {
      id: 3,
      title: "HTML & CSS",
      author: "Jon Duckett",
      price: 299,
      image: "data:image/png;base64,",
      description: "Design beautiful and responsive websites."
    },
    {
      id: 4,
      title: "Clean Code",
      author: "Robert C. Martin",
      price: 599,
      image: "https://m.media-amazon.com/images/I/41xShlnTZTL.jpg",
      description: "Write clean, readable, and maintainable code."
    },
    {
      id: 5,
      title: "The Pragmatic Programmer",
      author: "Andrew Hunt & David Thomas",
      price: 799,
      image: "https://m.media-amazon.com/images/I/41as+WafrFL.jpg",
      description: "Become a better software developer."
    },
    {
    id: 4,
    title: "Learning Python",
    author: "Mark Lutz",
    price: 699,
    image: "data:image/jpeg;base64,",
    description: "Comprehensive guide to Python programming."
  },
  {
    id: 3,
    title: "HTML & CSS Design",
    author: "Jon Duckett",
    price: 299,
    image: "data:image/jpeg;base64,",
    description: "Create beautiful and responsive websites."
  },
  {
    id: 6,
    title: "You Don’t Know JS",
    author: "Kyle Simpson",
    price: 459,
    image: "data:image/jpeg;base64,",
    description: "A deep explanation of modern JavaScript."
  },
  {
    id: 7,
    title: "Cracking the Coding Interview",
    author: "Gayle Laakmann McDowell",
    price: 799,
    image: "data:image/jpeg;base64,",
    description: "Prepare for your next technical interview."
  },
   {
    id: 8,
    title: "Design Patterns",
    author: "Erich Gamma",
    price: 849,
    image: "data:image/jpeg;base64,",
    description: "Elements of reusable object-oriented software."
  },
  {
    id: 9,
    title: "Eloquent JavaScript",
    author: "Marijn Haverbeke",
    price: 429,
    image: "data:image/jpeg;base64,",
    description: "A modern introduction to programming."
  },
  {
    id: 10,
    title: "Introduction to Algorithms",
    author: "Thomas H. Cormen",
    price: 999,
    image: "data:image/jpeg;base64,",
    description: "Comprehensive book on algorithms."
  },
  {
    id: 12,
    title: "Refactoring",
    author: "Martin Fowler",
    price: 899,
    image: "data:image/jpeg;base64,",
    description: "Improving the design of existing code with proven refactoring techniques."
  }
  ];


  // Selected book (for details)
  const [selectedBook, setSelectedBook] = useState(null);

  // Cart
  const [cart, setCart] = useState([]);

  // Add to cart function
  const addToCart = (book) => {
    setCart([...cart, book]);
    alert(`${book.title} added to cart`);
  };

  return (
    <section className="books">
      <h2>Books</h2>
      <p>Cart Items: {cart.length}</p>

      {/* BOOK LIST */}
      <div className="book-list">
        {booksData.map((book) => (
          <div
            className="book-card"
            key={book.id}
            onClick={() => setSelectedBook(book)}
          >
            <img src={book.image} alt={book.title} />
            <h4>{book.title}</h4>
            <p>Author: {book.author}</p>
            <p>₹{book.price}</p>
          </div>
        ))}
      </div>

      {/* BOOK DETAILS */}
      {selectedBook && (
        <div className="book-details">
          <h2>Book Details</h2>
          <img src={selectedBook.image} alt={selectedBook.title} />
          <h3>{selectedBook.title}</h3>
          <p><strong>Author:</strong> {selectedBook.author}</p>
          <p><strong>Price:</strong> ₹{selectedBook.price}</p>
          <p>{selectedBook.description}</p>

          <button onClick={() => addToCart(selectedBook)}>
            Add to Cart
          </button>

          <button onClick={() => setSelectedBook(null)}>
            Close
          </button>
        </div>
      )}
    </section>
  );
}

export default Books;
